const row = items[0].json;
items[0].json = {
  submissionId: row.id,
  company: row.company,
  rawBlob: row.raw_blob ?? row.rawBlob ?? '',
  createdAt: row.created_at ?? row.createdAt ?? '',
};
return items;

const raw = String($json.rawBlob || '');

const pick = (label) => {
  const escaped = label.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const match = raw.match(new RegExp(`${escaped}=([^|]+)`, 'i'));
  return match ? match[1].trim() : '';
};

