items[0].json = {
  ...$json,
  name: '',
  email: '',
  phone: '',
  product: '',
  quantity: '',
  city: '',
  channel: '',
  issue: '',
  profileUrl: '',
};

return items;

const j = items[0].json;
const category = /partner|event|pr/i.test(`${j.product} ${j.issue}`)
  ? 'partnership'
  : /dubbla|skadad|problem|fel/i.test(`${j.product} ${j.issue}`)
    ? 'support_case'
    : /offert|hotell|premium|antal|present|lobby/i.test(`${j.product} ${j.issue}`)
      ? 'bulk_order'
      : 'general_inquiry';

const payload = {
  submissionId: j.submissionId,
  company: j.company,
  name: j.name,
  email: j.email,
  phone: j.phone,
  product: j.product,
  quantity: j.quantity,
  city: j.city,
  category,
  issue: j.issue || `Importerad från ${j.company}`,
  source: 'n8n-legacy-regex-starter',
  profileUrl: j.profileUrl,
  rawBlob: j.rawBlob,
};

const body = JSON.stringify(payload).replace(/'/g, "'\\''");
items[0].json = {
  ...j,
  rewardPayload: payload,
  rewardWebhook: 'http://localhost:5678/webhook/legacy-reward-preview',
  rewardCurl: `curl -sS -X POST http://localhost:5678/webhook/legacy-reward-preview -H "Content-Type: application/json" -d '${body}' > preview.html`,
};
return items;
